/* horizontal panel */
const HPanel = memo(function HPanel({
  cat,
  active,
}: {
  cat: (typeof categories)[number];
  active: boolean;
}) {
  const itemsRef = useRef<HTMLDivElement>(null);
  const hasAnimated = useRef(false);
  const [hoveredIdx, setHoveredIdx] = useState<string>(cat.items[0].id);

  useEffect(() => {
    if (!active || hasAnimated.current) return;
    hasAnimated.current = true;
    gsap.fromTo(
      Array.from(itemsRef.current?.children ?? []),
      { x: -30, opacity: 0 },
      { x: 0, opacity: 1, duration: 0.5, stagger: 0.1, ease: "power2.out" },
    );
  }, [active]);

  const { Scheme } = cat;

  return (
    <div
      className="flex-shrink-0 h-[100dvh] w-screen flex items-center relative overflow-hidden"
      style={{ minWidth: "100vw", backgroundColor: cat.bg }}
    >
      <div className="w-full lg:h-full container mx-auto px-10 md:px-6 grid lg:grid-cols-2 gap-4 lg:gap-10 items-center relative z-10">
        {/* text side */}
        <div className="flex flex-col justify-center pt-6 lg:py-0">
          <h2
            className="font-display text-th-white leading-none mb-6 scramble-target"
            style={{ fontSize: "clamp(2rem, 6vw, 6rem)" }}
            data-text={cat.name}
          >
            {cat.name}
          </h2>

          <p className="text-th-light/45 text-sm lg:text-base leading-relaxed max-w-[38ch] mb-4 lg:mb-8 hidden lg:block">
            {cat.tagline}
          </p>

          <div ref={itemsRef} className="space-y-4">
            {cat.items.map((item) => {
              const active = hoveredIdx === item.id;
              return (
                <div
                  key={item.name}
                  className="flex items-start gap-4"
                  onMouseEnter={() => setHoveredIdx(item.id)}
                >
                  <span
                    className={`mt-[0.35rem] block h-px bg-th-red shrink-0 transition-all duration-300 ${active ? "w-8" : "w-5"}`}
                  />
                  <div>
                    <div
                      className="text-th-white text-md font-normal tracking-wide transition-transform duration-300 origin-left"
                      style={{ transform: active ? "scale(1.2)" : "scale(1)" }}
                    >
                      {item.name}
                    </div>
                    <div className="text-th-light/35 text-xs mt-0.5 hidden lg:block">
                      {item.desc}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          <a
            href={cat.href}
            className="mt-6 lg:mt-10 max-w-fit px-6 py-2.5 border border-th-red text-white/80 hover:bg-th-red hover:text-white text-[0.65rem] tracking-[0.35em] uppercase font-semibold transition-all duration-300"
          >
            Подробнее
          </a>
        </div>

        {/* visual side */}
        <div className="w-full flex items-center justify-center relative h-[40vh] lg:h-full">
          {/* radial glow */}
          <div className="absolute top-0 bottom-0 aspect-square bg-[radial-gradient(circle_at_50%_50%,rgba(168,0,0,0.2),transparent_65%)] pointer-events-none" />

          {/* Scheme area with aspect ratio lock */}
          <Scheme hoveredIdx={hoveredIdx} setHoveredIdx={setHoveredIdx} />
        </div>
      </div>
    </div>
  );
});

/* section */
export default function Products() {
  const headerRef = useRef<HTMLDivElement>(null);
  const pinRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const flickRef = useRef<HTMLDivElement>(null);

  const endRef = useRef<HTMLDivElement>(null);

  const [activePanel, setActivePanel] = useState(0);
  const activePanelRef = useRef(0);

  useEffect(() => {
    const scroller = document.getElementById("scroller")!;
    const ctx = gsap.context(() => {
      /* header reveal */
      gsap.fromTo(
        headerRef.current,
        { y: 50, opacity: 0 },
        {
          y: 0,
          opacity: 1,
          duration: 1,
          ease: "power3.out",
          scrollTrigger: {
            trigger: headerRef.current,
            start: "top 80%",
            scroller,
          },
        },
      );

      /* horizontal scroll animation */
      const animation = gsap.to(trackRef.current, {
        xPercent: -(2 / 3) * 100,
        // duration: 5,
        ease: "none",
      });

      ScrollTrigger.create({
        // trigger: pinRef.current,
        trigger: flickRef.current,
        // start: "top 0%",
        start: "top top",
        endTrigger: endRef.current,
        // end: "bottom 100%",
        end: "bottom bottom",
        // pin: true,
        // anticipatePin: 1,
        animation: animation,
        scrub: 1,
        scroller,
        invalidateOnRefresh: true,
        onUpdate: (self) => {
          const panel = Math.round(self.progress * 2);
          if (panel !== activePanelRef.current) {
            activePanelRef.current = panel;
            setActivePanel(panel);
          }
        },
      });

      // ST2: toggle scroll-snap on #scroller
      ScrollTrigger.create({
        trigger: flickRef.current,
        // start: "top -75px",
        start: "top top",

        endTrigger: endRef.current,
        // end: "bottom 110%",
        end: "bottom bottom",

        scroller,
        onEnter: () => scroller.classList.add("snap"),
        onEnterBack: () => scroller.classList.add("snap"),
        onLeaveBack: () => scroller.classList.remove("snap"),
        onLeave: () => scroller.classList.remove("snap"),
        onRefresh: (self) => {
          if (self.isActive) scroller.classList.add("snap");
        },
      });
    });
    const onResize = () => scroller.classList.remove("snap");
    window.addEventListener("resize", onResize);

    return () => {
      ctx.revert();
      window.removeEventListener("resize", onResize);
      scroller.classList.remove("snap");
    };
  }, []);

  return (
    <section id="products" className="bg-th-dark">
      {/* section header */}
      <div
        ref={headerRef}
        className="max-w-7xl mx-auto px-6 lg:px-16 pt-24 pb-16"
      >
        <div className="flex items-center gap-6 mb-6">
          <span className="block h-px w-10 bg-th-red" />
          <span className="text-th-light/50 text-[0.6rem] tracking-[0.45em] uppercase font-semibold">
            Каталог продукции
          </span>
        </div>
        <h2
          className="font-display text-th-white leading-none"
          style={{ fontSize: "clamp(3rem, 8vw, 7.5rem)" }}
        >
          ЧТО МЫ <span className="text-th-red">ДЕЛАЕМ</span>
        </h2>
        <p className="text-th-light/40 text-sm mt-4 max-w-[50ch] leading-relaxed">
          Три направления — один стандарт качества. Каждый коврик проектируется,
          обрабатывается и проходит контроль с точностью до миллиметра.
        </p>
      </div>

      {/* scrolling marquee */}
      <div className="overflow-hidden border-y border-th-red/15 bg-th-red/5 py-3">
        <div className="marquee-inner inline-flex gap-6">
          {Array(8)
            .fill(["АВТОКОВРИКИ", "ДЛЯ ДОМА", "ГАРАЖНЫЕ СИСТЕМЫ", "ТРИХЕКСА"])
            .flat()
            .map((t, i) => (
              <React.Fragment key={i}>
                <span
                  key={i}
                  className="font-display text-th-light/15 text-xl tracking-widest whitespace-nowrap"
                >
                  {t}
                </span>
                <span key={i + "dot"}>
                  <span className="text-th-red/40">·</span>
                </span>
              </React.Fragment>
            ))}
        </div>
      </div>

      <div ref={flickRef} className="relative">
        <div
          ref={pinRef}
          // className="absolute w-full h-[100dvh] overflow-x-hidden"
          className="sticky top-0 w-full h-[100dvh] overflow-x-hidden z-10"
        >
          {/* track — 3 × 100vw */}
          <div
            ref={trackRef}
            className="flex w-fit h-full will-change-transform"
          >
            {categories.map((cat, i) => (
              <HPanel key={cat.id} cat={cat} active={activePanel === i} />
            ))}
          </div>

          {/* progress dots */}
          <div
            style={{
              position: "absolute",
              bottom: 32,
              left: "50%",
              transform: "translateX(-50%)",
              display: "flex",
              gap: 10,
              zIndex: 10,
            }}
          >
            {categories.map((cat, i) => (
              <div
                key={cat.id}
                style={{
                  width: activePanel === i ? 24 : 8,
                  height: 8,
                  borderRadius: 4,
                  backgroundColor:
                    activePanel === i ? "#A80000" : "rgba(244,244,244,0.2)",
                  transition: "all 0.3s ease",
                }}
              />
            ))}
          </div>
        </div>

        {/* fake snap targets for panels 2 & 3 */}
        {categories.map((_, i) => (
          <div
            key={i}
            ref={i === categories.length - 1 ? endRef : undefined}
            className="h-[100dvh] snap-center snap-always"
            style={{ marginTop: i === 0 ? "-100dvh" : undefined }}
          />
        ))}
      </div>
    </section>
  );
}
